#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int n,m,k,q,vis[N],dis[N],f[N];
vector<int> g[N];
int find(int x)
{
	if(f[x]==x) return x;
	return f[x]=find(f[x]);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>k>>q;
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	for(int i=1;i<=q;i++)
	{
		memset(vis,0,sizeof(vis));
		for(int j=1;j<=n;j++) f[j]=j;
		for(int j=1;j<=k;j++)
		{
			cin>>dis[j];
			vis[dis[j]]=1;
		}
		for(int j=1;j<=n;j++)
		{
			if(vis[j]) continue;
			for(int kk=0;kk<g[j].size();kk++)
			{
				int v=g[j][kk];
				if(vis[v]) continue;
				f[find(j)]=find(v);
			}
		}
		for(int j=1;j<=k;j++)
		{
			vis[dis[j]]=0;
			for(int kk=0;kk<g[dis[j]].size();kk++)
			{
				int v=g[dis[j]][kk];
				if(vis[v]) continue;
				f[find(dis[j])]=find(v);
			}
			if((find(dis[j])!=find(dis[j-1]))&&(j!=1))
			{
				cout<<"No\n";
				goto end;
			}
		}
		cout<<"Yes\n";
		end: ;
	}
	return 0;
}
